/*
* Get Month of the submission Date
* by Ana Castillo
*/
//Set Submission date
let submissionDate = this.YQP_SUBMISSION_DATE;
//Validate no empty
if (submissionDate != "" && submissionDate != null && submissionDate != undefined) {
    //Get only the month
    let month = submissionDate.split("-");
    month = month[1];
    return month;
} else {
    return "";
}

/*
* Validate Other Source (Required-> YES, No required-> NO)
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Validate Other
    if (this.YQP_SOURCE == "Other") {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Calc Total Reinsurance Broker Forte Total
* by Ana Castillo
*/
//Set parameters to calc
let totalFortePremium = this.YQP_TOTAL_PREMIUM_FINAL;
totalFortePremium = parseFloat(totalFortePremium);
let totalBrokerPercentage = this.YQP_TOTAL_BROKER_DEDUCTION_PERCENTAGE;
//Validate no empety fields
if (totalBrokerPercentage != "" && totalBrokerPercentage != null &&
    totalFortePremium != "" && totalFortePremium != null) {
    //Get Percentage
    totalBrokerPercentage = totalBrokerPercentage / 100;
    //Do it negative
    totalBrokerPercentage = totalBrokerPercentage * (-1);
    //Calc Total Reinsurance Broker with no losses
    let totalReinsuranceBroker = Math.round((totalFortePremium * totalBrokerPercentage + Number.EPSILON) * 100) / 100
    return totalReinsuranceBroker;
} else {
    return 0;
}

/*
* Calc Total REinsurance Commission Share Forte Total
* by Ana Castillo
*/
//No rows on the record list
if (this.YQP_REINSURER_INFORMATION == null) {
    return "";
} else {
    //Get all rows of the record list
    let reinsurerGridLen = this.YQP_REINSURER_INFORMATION.length;
    let totalBrokerDeduction = 0;
    for (let t = 0; t < reinsurerGridLen; t++) {
        //Sum all Share values of Reinsurer record list
        let brokerDeduction = this.YQP_REINSURER_INFORMATION[t]["YQP_BROKER_DEDUCTION_USD"] * 1;
        totalBrokerDeduction += brokerDeduction;
    }
    return totalBrokerDeduction;
}

/*
* Calc Total Net Technical Forte Total
* by Ana Castillo
*/
//Set parameters to calc
let forteTotalPremium = this.YQP_TOTAL_PREMIUM_FINAL;
forteTotalPremium = parseFloat(forteTotalPremium);
let totalReinsuranceBroker = this.YQP_TOTAL_REINSURANCE_COMMISION_BROKER;
//Validate no empty fields
if (forteTotalPremium != "" && forteTotalPremium != null) {
    if (totalReinsuranceBroker == "" || totalReinsuranceBroker == null) {
        totalReinsuranceBroker = 0;
    }
    //Calc Total Net technical round with no losses
    let totalNetTechnical = Math.round((forteTotalPremium + totalReinsuranceBroker + Number.EPSILON) * 100) / 100;
    return totalNetTechnical;
} else {
    return "";
}

/*
* Calc Total Net Premium Share Forte Total
* by Ana Castillo
*/
//Set parameters to calc
var premiumShare = this.YQP_PREMIUM_SHARE;
var totalCommisionShare = this.YQP_TOTAL_REINSURANCE_COMMISSION_SHARE;
//Validate no empty fields
if (premiumShare != "" && premiumShare != null) {
    if (totalCommisionShare == "" || totalCommisionShare == null) {
        totalCommisionShare = 0;
    }
    //Calc Total Net Premium Share round with no losses
    let totalNetPremiumShare = Math.round((premiumShare + totalCommisionShare + Number.EPSILON) * 100) / 100;
    return totalNetPremiumShare;
} else {
    return "";
}

/*
* Calc Total Tax Gross Share Forte Total
* by Ana Castillo
*/
//No rows on record list
if (this.YQP_REINSURER_INFORMATION == null) {
    return "";
} else {
    //Get rows of the record list
    let reinsurerGridLen = this.YQP_REINSURER_INFORMATION.length;
    let totalTaxGrossShare = 0;
    for (let t = 0; t < reinsurerGridLen; t++) {
        //Sum Tax gross share of Reinsurer Information record list
        let taxGross = this.YQP_REINSURER_INFORMATION[t]["YQP_TAX_GROSS_SHARE"] * 1;
        totalTaxGrossShare += taxGross;
    }
    return totalTaxGrossShare;
}

/*
* Calc Total Tax Net Share Forte Total
* by Ana Castillo
*/
//No rows on record list
if (this.YQP_REINSURER_INFORMATION == null) {
    return "";
} else {
    //Get rows of the record list
    let reinsurerGridLen = this.YQP_REINSURER_INFORMATION.length;
    let totalTaxNetShare = 0;
    for (let t = 0; t < reinsurerGridLen; t++) {
        //Sum Tax net share of Reinsurer Information record list
        let taxNet = this.YQP_REINSURER_INFORMATION[t]["YQP_TAX_NET_SHARE"] * 1;
        totalTaxNetShare += taxNet;
    }
    return totalTaxNetShare;
}

/*
* Calc Total Reserves Gross Share Forte Total
* by Ana Castillo
*/
//No rows on record list
if (this.YQP_REINSURER_INFORMATION == null) {
    return "";
} else {
    //Get rows of the record list
    let reinsurerGridLen = this.YQP_REINSURER_INFORMATION.length;
    let totalReservesGrossShare = 0;
    for (let t = 0; t < reinsurerGridLen; t++) {
        //Sum Reserves Gross Share of Reinsurer Information record list
        let grossShare = this.YQP_REINSURER_INFORMATION[t]["YQP_PREMIUM_RESERVES_GROSS_SHARE"] * 1;
        totalReservesGrossShare += grossShare;
    }
    return totalReservesGrossShare;
}

/*
* Calc Total Reserves Net Share Forte Total
* by Ana Castillo
*/
//No rows on record list
if (this.YQP_REINSURER_INFORMATION == null) {
    return "";
} else {
    //Get rows of the record list
    let reinsurerGridLen = this.YQP_REINSURER_INFORMATION.length;
    let totalReservesNetShare = 0;
    for (let t = 0; t < reinsurerGridLen; t++) {
        //Sum Reserves Net Share of Reinsurer Information record list
        let netShare = this.YQP_REINSURER_INFORMATION[t]["YQP_PREMIUM_RESERVES_NET_SHARE"] * 1;
        totalReservesNetShare += netShare;
    }
    return totalReservesNetShare;
}

/*
* Calc Total Forte Fee Percentage Forte Total
* by Ana Castillo
*/
//Set Parameters to calc
let totalForteFee = this.YQP_TOTAL_FORTE_FEE;
let netTechnicalShare = this.YQP_TOTAL_NET_TECHNICAL_PREMIUM_SHARE;
//Validate no empty values
if (totalForteFee != "" && netTechnicalShare != "" &&
    totalForteFee != null && netTechnicalShare != null) {
    //Calc Forte Fee Percentage
    let totalForteFeePercentage = ((totalForteFee / netTechnicalShare) * (-1)) * 100;
    //Calc round forte fee with no losses
    totalForteFeePercentage = Math.round((totalForteFeePercentage + Number.EPSILON) * 100) / 100
    return totalForteFeePercentage;
} else {
    return "";
}

/*
* Calc Total Forte Fee Forte Total
* by Ana Castillo
*/
//No rows on the record list
if (this.YQP_REINSURER_INFORMATION == null) {
    return "";
} else {
    //Get rows of the record list
    let reinsurerGridLen = this.YQP_REINSURER_INFORMATION.length;
    let totalForteFee = 0;
    for (let t = 0; t < reinsurerGridLen; t++) {
        //Sum Forte Fee of Reinsurer Information record list
        let forteFee = this.YQP_REINSURER_INFORMATION[t]["YQP_FORTE_FEE"] * 1;
        totalForteFee += forteFee;
    }
    return totalForteFee;
}

/*
* Calc Ceded Premium Share Forte Total
* by Ana Castillo
* modified by Helen Callisaya
*/
//Set parameters to calc
let totalTechnicalPremium = this.YQP_TOTAL_NET_TECHNICAL_PREMIUM_SHARE;
totalTechnicalPremium = parseFloat(totalTechnicalPremium);
let totalTaxGrossShare = this.YQP_TOTAL_TAX_GROSS_SHARE;
if (totalTaxGrossShare == "NaN" || totalTaxGrossShare == undefined) totalTaxGrossShare = 0;
let totalTaxNetShare = this.YQP_TOTAL_TAX_NET_SHARE;
if (totalTaxNetShare == "NaN" || totalTaxNetShare == undefined) totalTaxNetShare = 0;
let totalReservesGrossShare = this.YQP_TOTAL_PREMIUM_RESERVES_GROSS_SHARE;
if (totalReservesGrossShare == "NaN" || totalReservesGrossShare == undefined) totalReservesGrossShare = 0;
let totalReservesNetShare = this.YQP_TOTAL_PREMIUM_RESERVES_NET_SHARE;
if (totalReservesNetShare == "NaN" || totalReservesNetShare == undefined) totalReservesNetShare = 0;
let totalForteFee = this.YQP_TOTAL_FORTE_FEE;
//Validate no empty fields
if (totalTechnicalPremium != "" && totalForteFee != "" &&
    totalTechnicalPremium != null && totalForteFee != null) {
    //Sum all fields
    let totalCededShare = totalTechnicalPremium + totalTaxGrossShare + totalTaxNetShare + totalReservesGrossShare + totalReservesNetShare + totalForteFee;
    //Calc round Ceded share with no losses
    totalCededShare = Math.round((totalCededShare + Number.EPSILON) * 100) / 100;
    return totalCededShare;
} else {
    return 0;
}

/*
* Calc Show request error
* by Helen Callisaya
*/
//validates if the FORTE_ERRORS.FORTE_ERROR_LOG variable has no errors
if (this.FORTE_ERRORS.FORTE_ERROR_LOG == "" || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == "no-error" || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == null || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == undefined) {
    return false;
} else {
    return true;
}

/*
* Calc Get the user id of the request 
* by Helen Callisaya
*/
return this._user.id;

/*
* Calc Get the user fullname of the request 
* by Helen Callisaya
*/
return this._user.fullname;

/*
* Calc Check if the variable exists
* by Helen Callisaya
*/
if (this.END_CASE_CAN_CONTINUE) {
    return 'YES';
} else {
    return 'NO';
}

